const SUPABASE_URL = 'https://wddatxgqhdiosuhcztex.supabase.co';
const BUCKET = 'app-assets';

return [{
  json: {
    supabaseUrl: SUPABASE_URL,
    bucket: BUCKET,
    style: 'Soft pastel Japanese kawaii manga style for children aged 6-12. Bright warm colors, rounded shapes, friendly and magical atmosphere. No text, no typography, no speech bubbles.',
    brandColors: {
      primary: '#FF8A65',
      background: '#FFFCF5',
      secondary: '#7EC8E3',
      fantasy: '#C8A2C8',
      space: '#7EC8E3',
      ocean: '#4FC3F7'
    }
  }
}];

const items = $input.all();
const now = new Date().toISOString();

return items.map(item => {
  const d = item.json;
  return {
    json: {
      type: d.type,
      name: d.name,
      description: d.description || '',
      image_url: `${d.supabaseUrl}/storage/v1/object/public/${d.bucket}/${d.storagePath}`,
      storage_path: d.storagePath,
      universe_type: d.universeType || null,
      gender: d.gender || 'all',
      display_order: d.displayOrder || 0,
      created_at: now
    }
  };
});
